SELECT id, correlation_id AS correlationId, user_id AS userId, session_id AS sessionId, started_at AS startedAt, finished_at AS finishedAt, duration_ms AS durationMs, status, steps_count AS stepsCount, tool_calls AS toolCalls, error_message AS errorMessage, input_tokens AS inputTokens, output_tokens AS outputTokens, trace_payload AS tracePayload, pattern_analyzed AS patternAnalyzed, created_at AS createdAt FROM execution_traces
AND status = #{status}
AND user_id = #{userId}
ORDER BY started_at DESC, id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM execution_traces


        AND status = #{status}


        AND user_id = #{userId}

SELECT COUNT(1)
FROM execution_traces
WHERE started_at >= #{since}

SELECT COUNT(1)
FROM execution_traces
WHERE started_at >= #{since}
  AND status = #{status}

SELECT duration_ms
FROM execution_traces
WHERE started_at >= #{since}
  AND duration_ms IS NOT NULL
ORDER BY duration_ms ASC
LIMIT #{limit}

SELECT COUNT(1)
FROM execution_traces
WHERE started_at >= #{from}
  AND started_at < #{to}

SELECT COUNT(1)
FROM execution_traces
WHERE started_at >= #{from}
  AND started_at < #{to}
  AND status = #{status}

SELECT AVG(duration_ms)
FROM execution_traces
WHERE started_at >= #{from}
  AND started_at < #{to}
  AND duration_ms IS NOT NULL

SELECT duration_ms
FROM execution_traces
WHERE started_at >= #{from}
  AND started_at < #{to}
  AND duration_ms IS NOT NULL
ORDER BY duration_ms ASC
LIMIT #{limit}
